import { useFrame } from "@react-three/fiber";
import { useGLTF } from "@react-three/drei";
import gsap from "gsap";
import { useEffect, useRef, useMemo } from "react";
import * as THREE from 'three';
import { sharedShadowMaterial, } from '../View/sharedMaterial';
import { _propsByZ } from '../View/BatchedWorldView';
import { PLAYER_IDLE_DELAY_MS, SUN_OFFSET } from '../Logic/constants';
import ExplosionEffect from "../Effects/ExplosionEffect";
import FireFBM from "../Effects/FireFBM";
import Feathers from "../Effects/Feathers";
import { Physics } from "../Logic/PhysicsEngine";
import { useGameStore } from "../Logic/store";
import Chicken from "./Chicken";
import ChickenSkin from "./ChickenSkin";
import Roasted from "./Roasted";
import EquippedItems from "./EquippedItems";
import { SoundManager } from "../Effects/SoundManager";
import { useWorld } from "../Logic/GameWorldContext";
import { createChickenDeformMaterial, createSkinDeformMaterial, createGoldDeformMaterial, createFireSurfaceMaterial, createAuroraDeformMaterial } from "./chickenDeformMaterial";

function FireChickenInGame({ visible, deformMat, deformUniforms }) {
    const { mat: fireMat, uniforms: fireUniforms } = useMemo(
        () => createFireSurfaceMaterial(deformUniforms), [deformUniforms]
    );
    useFrame(({ clock }) => { fireUniforms.uTime.value = clock.elapsedTime; });
    return (
        <ChickenSkin visible={visible} parts={[
            { names: ['chickenFire'],                          material: deformMat },
            { names: ['chickenFireHead1', 'chickenFireHead2'], material: fireMat   },
        ]} />
    );
}

function GoldChickenInGame({ visible, deformUniforms }) {
    const { mat: goldMat } = useMemo(
        () => createGoldDeformMaterial(deformUniforms), [deformUniforms]
    );
    return (
        <ChickenSkin visible={visible} parts={[
            { names: ['chickenGold', 'chickenGoldDeagL', 'chickenGoldDeagR'], material: goldMat },
        ]} />
    );
}

// Multi-mesh chickens using the base vertexColor chicken material
function MultiMeshChickenInGame({ visible, deformMat, meshNames }) {
    return (
        <ChickenSkin visible={visible} parts={[
            { names: meshNames, material: deformMat },
        ]} />
    );
}

const TERRORIST_MESHES = ['chickenT', 'chickenTAmmo', 'chickenTBandana', 'chickenTC4'];
const CT_MESHES        = ['chickenCT', 'chickenCTDiffuser', 'chickenCTFBI', 'chickenCTSas'];
const GHOST_MESHES     = ['chickenGhost', 'chickenGhostBlanket', 'chickenGhostEyeL', 'chickenGhostEyeR', 'chickenGhostMouth'];

const AURORA_OVERLAYS = {
    15: 'chickenAuroraJottaaa',
    16: 'chickenAuroraMaj3r',
    17: 'chickenAuroraWicadia',
    18: 'chickenAuroraWoxic',
    19: 'chickenAuroraXantares',
};

function AuroraChickenInGame({ visible, deformMat, deformUniforms, overlayName }) {
    const { mat: auroraMat } = useMemo(
        () => createAuroraDeformMaterial(deformUniforms), [deformUniforms]
    );
    return (
        <ChickenSkin visible={visible} parts={[
            { names: ['chickenAurora'],  material: deformMat  },
            { names: [overlayName],      material: auroraMat  },
        ]} />
    );
}

export default function Player() {
    const meshRef          = useRef();
    const shadowChickenRef = useRef();
    const explosionRef     = useRef();
    const fireRef          = useRef();
    const shadowBaseY      = useRef(null);
    const prevPlayerY      = useRef(null);
    const prevPrevPlayerY  = useRef(null);
    const world            = useWorld();

    const { nodes: shadowNodes } = useGLTF('/models/shadow.glb');
    const shadowChickenGeo = shadowNodes.shadow_chicken?.geometry ?? null;

    const isDead              = useGameStore(s => s.isDead);
    const deathType           = useGameStore(s => s.deathType);
    const invulnerabilityActive = useGameStore(s => s.invulnerabilityActive);
    const explosionPos  = useGameStore(s => s.explosionPos);
    const isMoving      = useGameStore(s => s.isMoving);
    const isStarted     = useGameStore(s => s.isStarted);
    const restartTrigger = useGameStore(s => s.restartTrigger);
    const equippedItems  = useGameStore(s => s.equippedItems);
    const chickenColorIdx = useGameStore(s => s.chickenColorIdx);

    // ── Deform material — один инстанс на всё время жизни компонента ───────────
    const { mat: deformMat, uniforms: deformUniforms } = useMemo(
        () => createChickenDeformMaterial(), []
    );
    const { mat: skinDeformMat, uniforms: skinDeformUniforms } = useMemo(
        () => createSkinDeformMaterial(), []
    );

    // ── Щит неуязвимости — геометрия и материал создаются один раз ──────────
    const shieldGeo = useMemo(() => new THREE.SphereGeometry(0.78, 18, 14), []);
    const shieldMat = useMemo(() => new THREE.MeshStandardMaterial({
        color: '#44aaff', transparent: true, opacity: 0.18,
        side: THREE.BackSide, depthWrite: false, roughness: 0.2, metalness: 0.1,
    }), []);

    const SKIN_MODELS  = {  };
    const ATLAS_MODELS = { 5: 'chickenCS16', 6: 'chickenMoorhuhn', 7: 'chickenRubber', 8: 'chickenRoasted', 11: 'chickenEgg' };
    const isSkinModel       = chickenColorIdx in SKIN_MODELS;
    const isAtlasModel      = chickenColorIdx in ATLAS_MODELS;
    const isFireModel       = chickenColorIdx === 9;
    const isGoldModel       = chickenColorIdx === 10;
    const isTerroristModel  = chickenColorIdx === 12;
    const isCTModel         = chickenColorIdx === 13;
    const isGhostModel      = chickenColorIdx === 14;
    const isAuroraModel     = chickenColorIdx in AURORA_OVERLAYS;

    // Кладём uniforms в world, чтобы PlayerController мог анимировать их напрямую
    useEffect(() => {
        world.deformUniforms = isSkinModel ? skinDeformUniforms : deformUniforms;
        return () => { world.deformUniforms = null; };
    }, [isSkinModel]);

    // ── Idle анимация через uTwist (взгляд влево/вправо) и uBend (клевок) ──────
    const idleTimer  = useRef(null);
    const idleTween  = useRef(null);
    const isIdling   = useRef(false);

    const startIdle = () => {
        if (isIdling.current) return;
        isIdling.current = true;
        SoundManager.play('chickenIdle', false);
        const u = deformUniforms;

        idleTween.current = gsap.timeline({ repeat: -1, repeatDelay: 0.5 })
            // Клевок 1 — uBend вперёд
            .to(u.uBend, { value:  0.55, duration: 0.11, ease: 'power2.in'  })
            .to(u.uBend, { value: -0.12, duration: 0.16, ease: 'power2.out' })
            .to(u.uBend, { value:  0,    duration: 0.10 })
            .to({}, { duration: 0.4 })
            // Клевок 2 (короче)
            .to(u.uBend, { value:  0.42, duration: 0.09, ease: 'power2.in'  })
            .to(u.uBend, { value: -0.09, duration: 0.13, ease: 'power2.out' })
            .to(u.uBend, { value:  0,    duration: 0.09 })
            .to({}, { duration: 0.3 })
            // Twist влево — верхняя часть тела крутится, как будто смотрит в сторону
            .to(u.uTwist, { value:  0.55, duration: 0.22, ease: 'sine.inOut' })
            .to({}, { duration: 0.28 })
            .to(u.uTwist, { value:  0,    duration: 0.18, ease: 'sine.inOut' })
            .to({}, { duration: 0.2 })
            // Twist вправо
            .to(u.uTwist, { value: -0.55, duration: 0.20, ease: 'sine.inOut' })
            .to({}, { duration: 0.28 })
            .to(u.uTwist, { value:  0,    duration: 0.18, ease: 'sine.inOut' });
    };

    const stopIdle = () => {
        if (!isIdling.current) return;
        isIdling.current = false;
        if (idleTween.current) { idleTween.current.kill(); idleTween.current = null; }
        // Плавный возврат деформаций в ноль
        gsap.to(deformUniforms.uBend,  { value: 0, duration: 0.12 });
        gsap.to(deformUniforms.uTwist, { value: 0, duration: 0.12 });
        if (idleTimer.current) { clearTimeout(idleTimer.current); idleTimer.current = null; }
    };

    useEffect(() => {
        if (isDead) { stopIdle(); return; }
        if (isMoving) {
            stopIdle();
        } else {
            idleTimer.current = setTimeout(startIdle, PLAYER_IDLE_DELAY_MS);
        }
        return () => { if (idleTimer.current) clearTimeout(idleTimer.current); };
    }, [isMoving, isDead]);

    // ── Убиваем все GSAP-твины при размонтировании компонента ────────────────
    useEffect(() => {
        return () => {
            stopIdle();
            gsap.killTweensOf(meshRef.current?.position);
            gsap.killTweensOf(meshRef.current?.rotation);
            gsap.killTweensOf(meshRef.current?.scale);
            gsap.killTweensOf(deformUniforms.uStretch);
            gsap.killTweensOf(deformUniforms.uTwist);
            gsap.killTweensOf(deformUniforms.uBend);
        };
    }, []);

    useEffect(() => {
        if (invulnerabilityActive) SoundManager.play('chickenPanic', false);
    }, [invulnerabilityActive]);

    useEffect(() => {
        world.playerRef = meshRef;
        return () => { world.playerRef = null; };
    }, []);

    // On game start: hop through waypoints to [0,0,0]
    useEffect(() => {
        if (!isStarted || !meshRef.current) return;
        const mesh = meshRef.current;
        const u    = deformUniforms;

        stopIdle();
        gsap.killTweensOf(mesh.position);
        gsap.killTweensOf(mesh.rotation);
        gsap.killTweensOf(u.uStretch);
        gsap.killTweensOf(u.uTwist);
        gsap.killTweensOf(u.uBend);

        u.uStretch.value = 1.0;
        u.uTwist.value   = 0;
        u.uBend.value    = 0;

        // Start pos = WAYPOINTS[0]; hops go from index 1 onward (19 hops, 1 cell each)
        const WAYPOINTS = [
            [0.7,  -1.75, -12.5],
            [0.7,  -1.75, -11.5],
            [0.7,  -1.75, -10.5],
            [0.7,  -1.75,  -9.5],
            [-0.3, -1.75,  -9.5],
            [-0.3, -1.75,  -8.5],
            [-1.3, -1.15,  -8.5],
            [-2.3,  -0.9,  -8.5],
            [-3.3,  -0.9,  -8.5],
            [-3.3,  -0.9,  -7.5],
            [-3.3,  -0.9,  -6.5],
            [-3.3,   0.0,  -5.5],
            [-3,     0,    -5  ],
            [-3,     0,    -4  ],
            [-2,     0,    -3  ],
            [-1,     0,    -3  ],
            [0,      0,    -3  ],
            [0,      0,    -2  ],
            [0,      0,    -1  ],
            [0,      0,     0  ],
        ];

        const hops   = WAYPOINTS.slice(1); // skip start position
        const n      = hops.length;        // 19 hops
        const D_MIN  = 0.14;               // fastest hop (middle of journey)
        const JH     = 0.7;

        useGameStore.setState({ isIntroPlaying: true });
        const tl = gsap.timeline({ delay: 0.05 });
        let   t      = 0;

        for (let i = 0; i < n; i++) {
            const [tx, ty, tz] = hops[i];
            const [fx, fy, fz] = i === 0 ? WAYPOINTS[0] : hops[i - 1];
            const angle = Math.atan2(tx - fx, tz - fz);
            const peakY = Math.max(fy, ty) + JH;

            // Bell-curve speed: slow start → fast middle → slow end
            const progress = i / (n - 1);
            const speed    = 0.4 + 0.6 * Math.sin(Math.PI * progress);
            const D        = D_MIN / speed; // ~0.14s (fast) … ~0.35s (slow)

            // Sound every 3rd hop
            if (i % 3 === 0) tl.call(() => SoundManager.play('jump', false), null, t);

            tl.to(mesh.position, { x: tx, z: tz, duration: D, ease: 'power2.inOut' }, t);
            tl.to(mesh.position, {
                keyframes: [
                    { y: peakY, duration: D * 0.44, ease: 'power2.out' },
                    { y: ty,    duration: D * 0.56, ease: 'power3.in'  },
                ]
            }, t);
            tl.to(mesh.rotation, { y: angle, duration: Math.min(D * 0.4, 0.12) }, t);
            tl.to(u.uStretch, {
                keyframes: [
                    { value: 1.32, duration: D * 0.44, ease: 'sine.out'   },
                    { value: 1.04, duration: D * 0.32, ease: 'sine.in'    },
                    { value: 0.68, duration: D * 0.24, ease: 'power3.in'  },
                ]
            }, t);

            t += D;
        }

        // Reset deform after last hop
        tl.to(u.uStretch, { value: 1.0, duration: 0.18, ease: 'power2.out' }, t);
    }, [isStarted]);

    useFrame((_, delta) => {
        const player = meshRef.current;
        if (isDead || !player) return;
        const { isPaused } = useGameStore.getState();
        if (isPaused) return;

        // ── Breathing animation (continuous subtle chest rise/fall) ────────
        deformUniforms.uBreathe.value += delta;

        // ── Тень курицы на земле ──────────────────────────────────────────────
        if (shadowChickenRef.current) {
            const py    = player.position.y;
            const prev  = prevPlayerY.current;
            const pprev = prevPrevPlayerY.current;
            // Local minimum: was descending (pprev > prev), now ascending/stable (py >= prev)
            if (prev !== null && pprev !== null && pprev > prev && py >= prev)
                shadowBaseY.current = prev;
            if (shadowBaseY.current === null) shadowBaseY.current = py;
            prevPrevPlayerY.current = prev;
            prevPlayerY.current = py;

            const h = Math.max(py - shadowBaseY.current, 0);
            shadowChickenRef.current.position.set(
                player.position.x - (SUN_OFFSET[0] / SUN_OFFSET[1]) * h,
                shadowBaseY.current,
                player.position.z - (SUN_OFFSET[2] / SUN_OFFSET[1]) * h,
            );
            shadowChickenRef.current.rotation.y = player.rotation.y;
        }

        // ── Затемнение курицы от пропса в z-1, x-1 ───────────────────────────
        const px = player.position.x, pz = player.position.z;
        const rz = Math.round(pz) - 1;
        let minDist = Infinity;
        const _row = _propsByZ.get(rz);
        if (_row) { for (let _i = 0; _i < _row.length; _i++) minDist = Math.min(minDist, Math.abs(px - (_row[_i] - 1))); }
        const target = minDist < 1.5 ? 1 - minDist / 1.5 : 0;
        deformUniforms.uShadowFactor.value = THREE.MathUtils.lerp(
            deformUniforms.uShadowFactor.value, target, 0.12
        );

        const currentLog  = Physics.getLogUnderPlayer(world);
        const currentLily = Physics.getLilyUnderPlayer(world);

        if (currentLog && !isMoving) {
            player.position.x += currentLog.lastMove;
            currentLog.yOffset = THREE.MathUtils.lerp(currentLog.yOffset || 0, -0.12, 0.1);
            const inv = currentLog.direction > 0 ? 1 : -1;
            const targetRotX = (player.position.z - currentLog.z) * 0.2 * inv;
            const targetRotZ = (currentLog.x - player.position.x) * 0.1;
            currentLog.rotX = THREE.MathUtils.lerp(currentLog.rotX || 0, targetRotX, 0.1);
            currentLog.rotZ = THREE.MathUtils.lerp(currentLog.rotZ || 0, targetRotZ, 0.1);
        }

        if (currentLily && !isMoving) {
            currentLily.yOffset = THREE.MathUtils.lerp(currentLily.yOffset || 0, -0.1, 0.2);
        }
    });

    useEffect(() => {
        stopIdle();
        gsap.killTweensOf(meshRef.current.position);
        gsap.killTweensOf(meshRef.current.scale);
        gsap.killTweensOf(meshRef.current.rotation);
        gsap.killTweensOf(deformUniforms.uStretch);
        gsap.killTweensOf(deformUniforms.uTwist);
        gsap.killTweensOf(deformUniforms.uBend);
        deformUniforms.uStretch.value = 1.0;
        deformUniforms.uTwist.value   = 0.0;
        deformUniforms.uBend.value    = 0.0;
        if (meshRef.current) {
            const started = useGameStore.getState().isStarted;
            meshRef.current.position.set(
                started ? 0 : 0.7,
                started ? 0 : -1.75,
                started ? 0 : -12.5
            );
            // Face camera in menu (before first start), forward in game
            const facingY = started ? 0 : Math.PI;
            meshRef.current.rotation.set(0, facingY, 0);
            meshRef.current.scale.set(1, 1, 1);
            meshRef.current.visible = true;
        }
        world.playerRef = meshRef;
        fireRef.current?.stop();
    }, [restartTrigger]);

    useEffect(() => {
        if (isDead && meshRef.current) {
            const mesh = meshRef.current;
            SoundManager.play(deathType === 'Sniper' ? 'deathSniper' : 'death');
            if (deathType === 'HE')      SoundManager.play('grenadeExplosion', false);
            if (deathType === 'C4')      SoundManager.play('explosion', false);
            if (deathType === 'Molotov') SoundManager.play('molotov');

            if (deathType === "HE" || deathType === "C4" || deathType === "Molotov") {
                if (deathType === 'HE') {
                    explosionRef.current?.trigger(explosionPos[0], explosionPos[2], { scale: 0.5, bursts: 1 });
                } else if (deathType === 'C4') {
                    explosionRef.current?.trigger(explosionPos[0], explosionPos[2], { scale: 1.2, bursts: 3, spread: 2 });
                } else if (deathType === 'Molotov') {
                    fireRef.current?.start(explosionPos[0], explosionPos[2]);
                }
                const u = deformUniforms;
                const tl = gsap.timeline();

                // 1. Подброс вверх — резкий stretch
                tl.to(mesh.position, {
                    y: 2.2, z: mesh.position.z - 0.4,
                    duration: 0.38, ease: "power3.out"
                }, 0);
                tl.to(u.uStretch, { value: 1.7,  duration: 0.25, ease: "power2.out" }, 0);
                tl.to(u.uTwist,   { value: Math.PI * 0.6, duration: 0.42, ease: "sine.inOut" }, 0);

                // 2. Пик — небольшое зависание + squash на вершине
                tl.to(mesh.position, { y: 2.4, duration: 0.12, ease: "power1.out" }, 0.36);
                tl.to(u.uStretch, { value: 0.75, duration: 0.12, ease: "power2.in" }, 0.36);

                // 3. Падение вниз — stretch нарастает по мере ускорения
                tl.to(mesh.position, { y: 0.0, duration: 0.44, ease: "power2.in"  }, 0.48);
                tl.to(u.uStretch,    { value: 1.65, duration: 0.38, ease: "power2.in" }, 0.48);

                // 4. Squash при ударе о землю — резкий сплюск
                tl.to(u.uStretch, { value: 0.22, duration: 0.08, ease: "power4.in"  }, 0.88);

                // 5. Bounce: вытягивается → чуть сплющивается → норма
                tl.to(u.uStretch, { value: 1.35, duration: 0.12, ease: "power2.out" }, 0.96);
                tl.to(u.uStretch, { value: 0.82, duration: 0.09, ease: "power2.in"  }, 1.08);
                tl.to(u.uStretch, { value: 1.0,  duration: 0.50, ease: "elastic.out(1, 0.4)" }, 1.17);

                // 6. Twist медленно гасится
                tl.to(u.uTwist, { value: 0, duration: 1.0, ease: "elastic.out(1, 0.35)" }, 1.0);

                // 7. Плавный завал на бок
                tl.to(mesh.rotation, { z: Math.PI * 0.5, duration: 0.9, ease: "power2.inOut" }, 1.5);
                tl.to(mesh.position, { y: -0.05, duration: 0.25, ease: "power2.in" }, 2.2);
            }

            if (deathType === "Drown") {
                SoundManager.play('drown');
                const u = deformUniforms;
                const tl = gsap.timeline();

                // Небольшой испуганный подскок
                tl.to(mesh.position, { y: 0.5, duration: 0.12, ease: "power2.out" }, 0);
                tl.to(u.uStretch,    { value: 1.5,  duration: 0.10, ease: "power2.out" }, 0);

                // Squash при падении на воду
                tl.to(mesh.position, { y: 0, duration: 0.10, ease: "power2.in" }, 0.12);
                tl.to(u.uStretch,    { value: 0.45, duration: 0.09, ease: "power3.in"  }, 0.22);
                tl.to(u.uStretch,    { value: 0.9,  duration: 0.08, ease: "power2.out" }, 0.31);

                // Медленное утопание
                tl.to(mesh.position, { y: -1.4, duration: 1.1, ease: "power2.in" }, 0.38);
                tl.to(u.uStretch,    { value: 0.08, duration: 1.1, ease: "power2.in" }, 0.38);
                tl.to(mesh.scale,    { x: 0.6, y: 1, z: 0.6, duration: 1.1, ease: "power2.in" }, 0.38);
            }

            if (deathType === "Sniper") {
                mesh.visible = false;
            }
        }
    }, [isDead, deathType]);

    const isRoasted = isDead && (deathType === 'HE' || deathType === 'C4' || deathType === 'Molotov');

    return (
        <>
            {shadowChickenGeo && (
                <mesh
                    ref={shadowChickenRef}
                    geometry={shadowChickenGeo}
                    material={sharedShadowMaterial}
                    renderOrder={1}
                />
            )}
            <group ref={ meshRef }>
                {isSkinModel
                    ? <ChickenSkin visible={ !isRoasted } modelName={ SKIN_MODELS[chickenColorIdx] } material={ skinDeformMat } />
                    : isAtlasModel      ? <ChickenSkin visible={ !isRoasted } modelName={ ATLAS_MODELS[chickenColorIdx] } material={ deformMat } />
                    : isFireModel       ? <FireChickenInGame visible={ !isRoasted } deformMat={ deformMat } deformUniforms={ deformUniforms } />
                    : isGoldModel       ? <GoldChickenInGame visible={ !isRoasted } deformUniforms={ deformUniforms } />
                    : isTerroristModel  ? <MultiMeshChickenInGame visible={ !isRoasted } deformMat={ deformMat } meshNames={ TERRORIST_MESHES } />
                    : isCTModel         ? <MultiMeshChickenInGame visible={ !isRoasted } deformMat={ deformMat } meshNames={ CT_MESHES } />
                    : isGhostModel      ? <MultiMeshChickenInGame visible={ !isRoasted } deformMat={ deformMat } meshNames={ GHOST_MESHES } />
                    : isAuroraModel     ? <AuroraChickenInGame visible={ !isRoasted } deformMat={ deformMat } deformUniforms={ deformUniforms } overlayName={ AURORA_OVERLAYS[chickenColorIdx] } />
                    : <Chicken visible={ !isRoasted } colorIdx={ chickenColorIdx } material={ deformMat } />
                }
                <Roasted visible={ isRoasted } material={ deformMat } />
                { !isRoasted && <EquippedItems equippedItems={ equippedItems } deformUniforms={ deformUniforms } /> }
                { invulnerabilityActive && (
                    <mesh position={[0, 0.45, 0]} geometry={shieldGeo} material={shieldMat} />
                )}
            </group>
            <ExplosionEffect ref={explosionRef} />
            <FireFBM ref={fireRef} />
            { isDead && <Feathers position={ [explosionPos[0], 0, explosionPos[2]] } /> }
        </>
    );
}