import React, { useEffect, useRef } from "react";
import { PhysicsManager } from "../Logic/PhysicsEngine";

const rand = () => Math.random().toString(36).slice(2);

export const Row = React.memo(({ row }) => {
    // Generate stable IDs once on mount — never changes for the lifetime of this row
    const idsRef = useRef(null);
    if (!idsRef.current) {
        const grenadeCount = row.config?.count ?? 0;
        const logOffsets   = row.config?.offsets ?? [];
        const lilyXs       = row.config?.lilys   ?? [];
        idsRef.current = {
            grenades: Array.from({ length: grenadeCount }, (_, i) => `gren-${row.z}-${i}-${rand()}`),
            logs:     logOffsets.map((_, i) => `log-${row.z}-${i}-${rand()}`),
            lilys:    lilyXs.map((_, i)    => `lily-${row.z}-${i}-${rand()}`),
            windows:  (row.windows ?? []).map((_, i) => `win-${row.z}-${i}-${rand()}`),
            props:    (row.props   ?? []).map((_, i) => `prop-${row.z}-${i}-${rand()}`),
            coins:    (row.coins   ?? []).map((_, i) => `coin-${row.z}-${i}-${rand()}`),
            medals:   (row.medals  ?? []).map((_, i) => `medal-${row.z}-${i}-${rand()}`),
        };
    }

    useEffect(() => {
        const ids = idsRef.current;
        const cfg = row.config;

        // ── Water ──────────────────────────────────────────────────────────────
        if (row.type === 'water') PhysicsManager.register('water', row.z);

        // ── Grenades ───────────────────────────────────────────────────────────
        if (row.type === 'road' && cfg) {
            const placed = [];
            ids.grenades.forEach((id, i) => {
                const minDist = 3;
                let safeX = ((i * 8 + 12) % 24) - 12;
                for (const px of placed) {
                    if (Math.abs(px - safeX) < minDist) {
                        safeX += minDist;
                        if (safeX > 12) safeX -= 24;
                    }
                }
                placed.push(safeX);
                PhysicsManager.register('obstacle', {
                    id, z: row.z, x: safeX,
                    speed: cfg.speed, direction: cfg.direction,
                    type: cfg.type || 'HE',
                    rotVel: [(Math.random()-0.5)*6, (Math.random()-0.5)*6, (Math.random()-0.5)*6],
                    rotation: [Math.random(), Math.random(), Math.random()],
                    phase: Math.random() * Math.PI * 2,
                });
            });
        }

        // ── Logs / Boats ───────────────────────────────────────────────────────
        if (row.type === 'water' && cfg && (cfg.type === 'Wooden' || cfg.type === 'Boat')) {
            ids.logs.forEach((id, i) => {
                PhysicsManager.register('log', {
                    id, z: row.z,
                    x: cfg.offsets[i] ?? 0,
                    speed: cfg.speed, direction: cfg.direction,
                    type: cfg.type, yOffset: 0,
                });
            });
        }

        // ── Lily pads ──────────────────────────────────────────────────────────
        if (row.type === 'water' && cfg?.type === 'lilys') {
            ids.lilys.forEach((id, i) => {
                PhysicsManager.register('lily', { id, z: row.z, x: cfg.lilys[i] });
            });
        }

        // ── Walls (windows) ────────────────────────────────────────────────────
        ids.windows.forEach((id, i) => {
            PhysicsManager.register('window', { id, z: row.z, x: row.windows[i] });
        });

        // ── Props (obstacles on forest rows) ───────────────────────────────────
        row.props?.forEach((p, i) => {
            PhysicsManager.register('prop', {
                id: ids.props[i], z: row.z, x: Math.round(p.x), type: p.type,
            });
        });

        // ── Coins ──────────────────────────────────────────────────────────────
        row.coins?.forEach((c, i) => {
            PhysicsManager.register('coin', {
                id: ids.coins[i], x: c.x, z: row.z, type: c.type,
                collected: false, phase: Math.random() * Math.PI * 2,
            });
        });

        // ── Medals ─────────────────────────────────────────────────────────────
        row.medals?.forEach((m, i) => {
            PhysicsManager.register('medal', {
                id: ids.medals[i], x: m.x, z: row.z, subtype: m.subtype,
                collected: false, phase: Math.random() * Math.PI * 2,
            });
        });

        return () => {
            if (row.type === 'water') PhysicsManager.remove('water', row.z);
            ids.grenades.forEach(id => PhysicsManager.remove('obstacle', id));
            ids.logs.forEach(id    => PhysicsManager.remove('log', id));
            ids.lilys.forEach(id   => PhysicsManager.remove('lily', id));
            ids.windows.forEach(id => PhysicsManager.remove('window', id));
            ids.props.forEach(id   => PhysicsManager.remove('prop', id));
            ids.coins.forEach(id   => PhysicsManager.remove('coin', id));
            ids.medals.forEach(id  => PhysicsManager.remove('medal', id));
        };
    }, [row.id]); // row.id = "row-{seed}-{z}" — stable per row, changes only on restart

    return null;
}, (prev, next) => prev.row.id === next.row.id);
