import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, useGLTF, Environment } from '@react-three/drei';
import { useMemo, useEffect, useState, useRef, useCallback, Suspense } from 'react';
import * as THREE from 'three';
import { SoundManager } from './Effects/SoundManager';

useGLTF.preload('/models/RIO.glb');
new THREE.TextureLoader().load('/images/medalRio2026Big.png');
fetch('/images/qwantani_mid_morning_puresky_1k.hdr');

// ── Конфети ────────────────────────────────────────────────────────────────────
const CONFETTI_COLORS = ['#ffd700','#ffaa00','#fff','#ffeeaa','#00d4ff','#ff6b6b','#a8ff78','#ff9ff3'];
const SHAPES = ['square','rect','circle'];

function createConfettiBatch(batchId, count) {
    const h = window.innerHeight, w = window.innerWidth, off = 80;
    return Array.from({ length: count }, (_, i) => {
        const side  = i < count / 2 ? -1 : 1;
        const spawnX = w / 2 + side * off;
        const aMin  = side < 0 ? -Math.PI : -Math.PI / 2 + 0.2;
        const aMax  = side < 0 ? -Math.PI / 2 - 0.2 : 0;
        const angle = aMin + Math.random() * (aMax - aMin);
        const tY    = h * (0.7 + Math.random() * 0.2) * 4;
        const spd   = tY / (Math.abs(Math.sin(angle)) || 0.01);
        return {
            id: `${batchId}_${i}`, cx: spawnX, cy: h,
            vx: Math.cos(angle) * spd, vy: Math.sin(angle) * spd,
            spin: (Math.random() - 0.5) * 900,
            size: 7 + Math.random() * 9,
            delay: Math.random() * 0.06,
            dur: 2.5 + Math.random() * 1.2,
            color: CONFETTI_COLORS[~~(Math.random() * CONFETTI_COLORS.length)],
            shape: SHAPES[~~(Math.random() * SHAPES.length)],
        };
    });
}

// ── Медаль (GLB) ───────────────────────────────────────────────────────────────
function MedalMesh({ groupRef, onMounted }) {
    const { scene } = useGLTF('/models/RIO.glb');

    const texture = useMemo(() => {
        const t = new THREE.TextureLoader().load('/images/medalRio2026Big.png');
        t.flipY = false;
        t.colorSpace = THREE.SRGBColorSpace;
        return t;
    }, []);

    useEffect(() => {
        const mat = new THREE.MeshStandardMaterial({
            map: texture, metalness: 0.88, roughness: 0.12, envMapIntensity: 2.2,
        });
        scene.traverse(child => { if (child.isMesh) child.material = mat; });
        const t = setTimeout(() => onMounted?.(), 80);
        return () => clearTimeout(t);
    }, [scene, texture, onMounted]);

    return <primitive ref={groupRef} object={scene} scale={0} position={[0, -3, 0]} />;
}

// ── Sparkles ───────────────────────────────────────────────────────────────────
const SPARKLE_COUNT = 26;

const SPARKLE_DATA = Array.from({ length: SPARKLE_COUNT }, () => ({
    tilt:    (Math.random() - 0.5) * Math.PI * 0.55,
    maxLife: 1.0 + Math.random() * 2.0,
}));

function _spawnParticle(maxLife) {
    const angle = Math.random() * Math.PI * 2;
    const speed = 0.12 + Math.random() * 0.32;
    const r     = 0.5 + Math.random() * 2.8;
    return {
        x: Math.cos(angle) * r, y: 0.0 + Math.random() * 3.8, z: Math.sin(angle) * r,
        vx: (Math.random() - 0.5) * speed, vy: 0.02 + Math.random() * 0.18, vz: (Math.random() - 0.5) * speed,
        life: maxLife, maxLife,
    };
}

// ── 3D сцена ───────────────────────────────────────────────────────────────────
const _camTarget = new THREE.Vector3();

function MedalScene({ onDone, orbitRef }) {
    const { camera }     = useThree();
    const medalRef       = useRef();
    const sparkleRefs    = useRef([]);
    const sparkleState   = useRef(SPARKLE_DATA.map(d => _spawnParticle(d.maxLife)));
    const sparkleOpacity = useRef(0);
    const anim           = useRef({ phase: 'rising', t: 0 });
    const firedRef       = useRef(false);
    const medalReady     = useRef(false);

    const MEDAL_ROT_X = -70 * Math.PI / 180;
    const RISE_DUR    = 2.8;

    const glowTexture = useMemo(() => {
        const W = 32, H = 64;
        const canvas = document.createElement('canvas');
        canvas.width = W; canvas.height = H;
        const ctx = canvas.getContext('2d');
        ctx.save();
        ctx.translate(W / 2, H / 2);
        ctx.scale(1, H / W);
        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, W / 2);
        grad.addColorStop(0.00, 'rgba(255, 230, 120, 1.0)');
        grad.addColorStop(0.18, 'rgba(255, 130,  10, 1.0)');
        grad.addColorStop(0.45, 'rgba(220,  60,   0, 0.55)');
        grad.addColorStop(0.75, 'rgba(160,  30,   0, 0.18)');
        grad.addColorStop(1.00, 'rgba(  0,   0,   0, 0.0)');
        ctx.fillStyle = grad;
        ctx.beginPath(); ctx.arc(0, 0, W / 2, 0, Math.PI * 2); ctx.fill();
        ctx.restore();
        return new THREE.CanvasTexture(canvas);
    }, []);

    const handleMedalMounted = useCallback(() => {
        const g = medalRef.current;
        if (g) {
            g.position.set(0, -3, 0);
            g.rotation.x = MEDAL_ROT_X;
            g.scale.setScalar(1.0);
        }
        medalReady.current = true;
    }, []);

    useFrame((_, delta) => {
        const a = anim.current;
        if (!medalReady.current) return;
        a.t += delta;

        if (a.phase === 'rising') {
            const p  = Math.min(a.t / RISE_DUR, 1);
            const em = 1 - Math.pow(1 - p, 3);
            const g  = medalRef.current;
            if (g) {
                g.position.y  = -3 + em * 3;        // -3 → 0
                g.rotation.x  = MEDAL_ROT_X * (1 - em);
                g.rotation.y += 0.55 * delta * (1 - em * 0.7);
                _lerpTarget(g.position.x, g.position.y, g.position.z, delta * 1.5);
            }
            sparkleOpacity.current = Math.min(sparkleOpacity.current + delta * 0.8, 1);
            _animateSparkles(delta);
            if (p >= 1) {
                a.phase = 'done';
                if (!firedRef.current) { firedRef.current = true; onDone?.(); }
            }
        }

        if (a.phase === 'done') {
            const g = medalRef.current;
            if (g) {
                g.rotation.y += 0.02 * delta;
            }
            _animateSparkles(delta);
        }

        function _lerpTarget(x, y, z, speed) {
            const ctrl = orbitRef?.current;
            if (!ctrl) return;
            _camTarget.set(x, y, z);
            ctrl.target.lerp(_camTarget, speed);
            ctrl.update();
        }

        function _animateSparkles(dt) {
            const sop = sparkleOpacity.current;
            const st  = sparkleState.current;
            sparkleRefs.current.forEach((mesh, i) => {
                if (!mesh) return;
                const s = st[i];
                const d = SPARKLE_DATA[i];
                s.life -= dt;
                if (s.life <= 0) { st[i] = _spawnParticle(d.maxLife); return; }
                s.x += s.vx * dt; s.y += s.vy * dt; s.z += s.vz * dt;
                s.vx += (Math.random() - 0.5) * 0.3 * dt;
                s.vy += (Math.random() - 0.5) * 0.15 * dt;
                s.vz += (Math.random() - 0.5) * 0.3 * dt;
                mesh.position.set(s.x, s.y, s.z);
                mesh.quaternion.copy(camera.quaternion);
                mesh.rotateZ(d.tilt);
                mesh.material.opacity = sop * Math.sin((1 - s.life / s.maxLife) * Math.PI);
            });
        }
    });

    return (
        <>
            <Suspense fallback={null}>
                <MedalMesh groupRef={medalRef} onMounted={handleMedalMounted} />
            </Suspense>

            {SPARKLE_DATA.map((_, i) => (
                <mesh key={i} ref={el => { sparkleRefs.current[i] = el; }}>
                    <planeGeometry args={[0.032, 0.064]} />
                    <meshBasicMaterial map={glowTexture} transparent opacity={0}
                        blending={THREE.AdditiveBlending} depthWrite={false} />
                </mesh>
            ))}
        </>
    );
}

// ── Главный компонент ──────────────────────────────────────────────────────────
export default function MedalReveal({ onClose }) {
    const [ready,    setReady]    = useState(false);
    const [flash,    setFlash]    = useState(false);
    const [confetti, setConfetti] = useState([]);
    const orbitRef = useRef();

    useEffect(() => {
        SoundManager.play('highscore');
        setFlash(true);
        const tFlash = setTimeout(() => setFlash(false), 480);
        let batchId = 0;
        const addBatch = () => {
            setConfetti(prev => {
                const next = [...prev, ...createConfettiBatch(batchId++, 15)];
                return next.length > 180 ? next.slice(-180) : next;
            });
        };
        addBatch();
        const iv = setInterval(addBatch, 150);
        const tStop  = setTimeout(() => clearInterval(iv), 3000);
        const tClear = setTimeout(() => setConfetti([]), 7500);
        return () => {
            clearTimeout(tFlash);
            clearInterval(iv);
            clearTimeout(tStop);
            clearTimeout(tClear);
        };
    }, []);

    const handleDone = useCallback(() => {
        setReady(true);
    }, []);

    return (
        <div style={{
            position: 'absolute', inset: 0, zIndex: 3000,
            background: 'rgba(0,0,0,0.15)',
            backdropFilter: 'blur(10px)',
            WebkitBackdropFilter: 'blur(10px)',
            fontFamily: 'monospace',
            animation: 'medalRevealIn 0.4s ease-out both',
        }}>
            <Canvas
                camera={{ position: [0, 0.5, 2.2], fov: 48 }}
                gl={{ antialias: true, alpha: true }}
                style={{ position: 'absolute', inset: 0, background: 'transparent' }}
            >
                <Environment
                    files="/images/qwantani_mid_morning_puresky_1k.hdr"
                    backgroundBlurriness={ 0.1 }
                    backgroundIntensity={ 1.5 }
                />
                <ambientLight intensity={13.25} />
                <directionalLight position={[3, 6, 4]}   intensity={7.2} color="#ffe8a0" />
                <directionalLight position={[-3, 4, -5]} intensity={4.6} color="#a0c8ff" />
                <pointLight position={[0, 1, 2]} intensity={4.0} color="#ffcc44" />

                <MedalScene onDone={handleDone} orbitRef={orbitRef} />

                <OrbitControls ref={orbitRef}
                    enablePan={true}
                    enableZoom={true} zoomSpeed={1.2}
                    minDistance={0.4} maxDistance={4}
                    autoRotate autoRotateSpeed={0.3}
                    minPolarAngle={Math.PI * 0.1}
                    maxPolarAngle={Math.PI * 0.82}
                />
            </Canvas>

            {flash && (
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 2150,
                    background: 'white', pointerEvents: 'none',
                    animation: 'flashBurst 0.5s ease-out forwards',
                }} />
            )}

            {confetti.map(p => {
                const br = p.shape === 'circle' ? '50%' : '2px';
                const w  = p.shape === 'rect' ? p.size * 0.5 : p.size;
                return (
                    <div key={p.id} style={{
                        position: 'fixed', left: p.cx, top: p.cy,
                        width: w, height: p.size,
                        background: p.color, borderRadius: br,
                        pointerEvents: 'none', zIndex: 2110,
                        animationName: 'confettiFly',
                        animationDuration: `${p.dur}s`,
                        animationDelay: `${p.delay}s`,
                        animationTimingFunction: 'cubic-bezier(0.25,0.46,0.45,0.94)',
                        animationFillMode: 'forwards',
                        '--vx': `${p.vx}px`, '--vy': `${p.vy}px`, '--spin': `${p.spin}deg`,
                    }} />
                );
            })}

            {ready && (
                <div style={{
                    position: 'absolute', top: '5%', left: 0, right: 0,
                    display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '6px',
                    pointerEvents: 'none',
                    animation: 'medalRevealIn 0.5s ease-out both',
                }}>
                    <div style={{ fontSize: '9px', letterSpacing: '4px', color: 'rgba(255,204,0,0.5)' }}>
                        MEDAL UNLOCKED
                    </div>
                    <div style={{
                        fontSize: 'clamp(22px,7vw,32px)', fontWeight: 900,
                        color: '#ffcc00', textShadow: '0 0 28px rgba(255,204,0,0.7)',
                    }}>
                        MVP RIO 2026
                    </div>
                </div>
            )}

            <div style={{
                position: 'absolute',
                bottom: 'max(env(safe-area-inset-bottom, 0px) + 70px, 90px)',
                left: 0, right: 0,
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px',
                opacity: ready ? 1 : 0,
                transition: 'opacity 0.5s ease-out',
                pointerEvents: ready ? 'auto' : 'none',
                zIndex: 2120,
            }}>
                <div style={{ fontSize: '10px', letterSpacing: '2px', color: 'rgba(255,255,255,0.28)', pointerEvents: 'none' }}>
                    DRAG TO ROTATE  ·  PINCH TO ZOOM
                </div>
                <button onPointerDown={onClose} style={{
                    padding: '14px 40px',
                    background: 'linear-gradient(135deg, #ffd700, #ffaa00)',
                    border: 'none', borderRadius: '8px',
                    color: '#000', fontWeight: 'bold',
                    fontSize: '13px', letterSpacing: '2px',
                    cursor: 'pointer', fontFamily: 'monospace',
                    boxShadow: '0 0 28px rgba(255,204,0,0.45)',
                    WebkitTapHighlightColor: 'transparent',
                    touchAction: 'manipulation',
                }}>
                    CHOOSE UPGRADE →
                </button>
            </div>

            <style>{`
                @keyframes medalRevealIn {
                    0%   { opacity: 0; transform: scale(1.06); }
                    100% { opacity: 1; transform: scale(1); }
                }
                @keyframes confettiFly {
                    0%   { transform: translate(0,0) rotate(0deg); opacity: 1; }
                    80%  { opacity: 1; }
                    100% { transform: translate(var(--vx),var(--vy)) rotate(var(--spin)); opacity: 0; }
                }
                @keyframes flashBurst {
                    0%   { opacity: 0.85; }
                    100% { opacity: 0; }
                }
            `}</style>
        </div>
    );
}
