// ── Бомба: таймер по центру экрана ───────────────────────────────────────────
function BombHUD() {
    const bombProgress = useGameStore(s => s.bombProgress);
    const progress = bombProgress;
    const secondsLeft = Math.ceil((1 - progress) * 5);
    const isUrgent = progress > 0.6;
    const circumference = 2 * Math.PI * 28;
    const dashOffset = circumference * (1 - progress);

    return (
        <div style={{
            position: 'absolute',
            top: '50%', left: '50%',
            transform: 'translate(-50%, -50%)',
            display: 'flex', flexDirection: 'column',
            alignItems: 'center', gap: '8px',
            pointerEvents: 'none',
            animation: isUrgent ? 'bombShake 0.15s infinite' : 'none',
            zIndex: 100,
        }}>
            <svg width="80" height="80" viewBox="0 0 80 80">
                {/* Фоновое кольцо */}
                <circle cx="40" cy="40" r="28" fill="none"
                    stroke="rgba(255,255,255,0.1)" strokeWidth="5" />
                {/* Прогресс */}
                <circle cx="40" cy="40" r="28" fill="none"
                    stroke={progress > 0.75 ? '#ff2200' : progress > 0.45 ? '#ff8800' : '#ffcc00'}
                    strokeWidth="5"
                    strokeLinecap="round"
                    strokeDasharray={circumference}
                    strokeDashoffset={dashOffset}
                    transform="rotate(-90 40 40)"
                    style={{ transition: 'stroke 0.3s' }}
                />
                {/* Иконка */}
                <text x="40" y="45" textAnchor="middle" fontSize="26" style={{ userSelect: 'none' }}>💣</text>
            </svg>
            <div style={{
                fontSize: 'clamp(16px, 5vw, 22px)',
                fontWeight: '900', fontFamily: 'monospace',
                color: progress > 0.75 ? '#ff2200' : '#ffcc00',
                textShadow: `0 0 12px ${progress > 0.75 ? '#ff0000' : '#ffcc0066'}`,
                letterSpacing: '2px',
            }}>
                {secondsLeft}s
            </div>
        </div>
    );
}

// ── Прицел снайпера — только экранный эффект (сам прицел в 3D) ───────────────
function SniperHUD() {
    const progress = useGameStore(s => s.sniperProgress);
    const alpha = Math.min(1, progress * 1.6);
    return (
        <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none', zIndex: 100, opacity: alpha, transition: 'opacity 0.15s' }}>
            {/* Тёмная маска вокруг прицела */}
            <div style={{
                position: 'absolute', inset: 0,
                background: `radial-gradient(circle at center, transparent ${26 - progress * 8}%, rgba(0,0,0,0.92) ${36 - progress * 6}%)`,
                transition: 'background 0.15s',
            }} />
            {/* Прицел */}
            <svg style={{ position: 'absolute', inset: 0, width: '100%', height: '100%' }} viewBox="0 0 100 100" preserveAspectRatio="xMidYMid meet">
                <line x1="2"  y1="50" x2="50" y2="50" stroke="rgba(0, 0, 0, 0.75)" strokeWidth="0.15" />
                <line x1="50" y1="50" x2="98" y2="50" stroke="rgba(0, 0, 0, 0.75)" strokeWidth="0.15" />
                <line x1="50" y1="2"  x2="50" y2="50" stroke="rgba(0, 0, 0, 0.75)" strokeWidth="0.15" />
                <line x1="50" y1="50" x2="50" y2="98" stroke="rgba(0, 0, 0, 0.75)" strokeWidth="0.15" />
            </svg>
            {progress > 0.3 && (
                <div style={{
                    position: 'absolute', bottom: '18%', left: 0, right: 0,
                    textAlign: 'center', fontSize: '9px', letterSpacing: '3px', fontFamily: 'monospace',
                    color: `rgba(255,60,60,${Math.min(1, (progress - 0.3) * 3)})`,
                    textShadow: '0 0 8px #ff0000',
                }}>
                    MOVE FORWARD
                </div>
            )}
        </div>
    );
}

