import * as THREE from 'three';
import { WATER_ROW_WIDTH, CAUSTICS_Y_OFFSET } from '../Logic/constants';

export { CAUSTICS_Y_OFFSET };

// ── Shared geometry (same width as water row, 1 segment — flat) ──────────────
export const causticsGeo = new THREE.PlaneGeometry(WATER_ROW_WIDTH, 1, 1, 1);

// ── Spritesheet caustics (8×8, 60 active frames, AdditiveBlending) ───────────
// Shader samples by world-space XZ coords (tiled every TILE units) so the
// pattern repeats naturally across the full WATER_ROW_WIDTH plane.
const _causticsMap = new THREE.TextureLoader().load('/images/caustics.png');
_causticsMap.colorSpace = THREE.SRGBColorSpace;

export const causticsMaterial = new THREE.ShaderMaterial({
    transparent: true,
    depthWrite:  false,
    blending:    THREE.AdditiveBlending,
    side:        THREE.FrontSide,
    uniforms: {
        uMap:   { value: _causticsMap },
        uFrame: { value: 0 },            // current frame index 0..59
    },
    vertexShader: /* glsl */`
varying vec3 vWorldPos;
varying vec2 vUv;
void main() {
    #ifdef USE_INSTANCING
    vec4 world = instanceMatrix * vec4(position, 1.0);
    #else
    vec4 world = modelMatrix * vec4(position, 1.0);
    #endif
    vWorldPos   = world.xyz;
    vUv         = uv;
    gl_Position = projectionMatrix * viewMatrix * world;
}
`,
    fragmentShader: /* glsl */`
uniform sampler2D uMap;
uniform float     uFrame;
varying vec3      vWorldPos;
varying vec2      vUv;

const float COLS = 8.0;
const float ROWS = 8.0;
const float TILE   = 4.5;  // world units per tile (X)
const float Z_SCALE = 0.25; // <1 растягивает, >1 сжимает по Z
const float CA   = 0.015; // chromatic aberration

// Sample one caustics layer with chromatic aberration
vec4 sampleLayer(vec2 tiled, vec2 base, vec2 cell) {
    float r = texture2D(uMap, base + fract(tiled + vec2( CA,  0.0)) * cell).r;
    float g = texture2D(uMap, base + fract(tiled               ) * cell).g;
    float b = texture2D(uMap, base + fract(tiled + vec2( 0.0, -CA)) * cell).b;
    float a = texture2D(uMap, base + fract(tiled) * cell).a;
    return vec4(r, g, b, a);
}

void main() {
    float col = mod(uFrame, COLS);
    float row = ROWS - 1.0 - floor(uFrame / COLS);
    vec2  base = vec2(col, row) / vec2(COLS, ROWS);
    vec2  cell = vec2(1.0 / COLS, 1.0 / ROWS);

    // X — world-space (бесшовно между рядами), Z — local UV (всегда 0→1 на глубину ряда)
    vec2 wp = vec2(vWorldPos.x / TILE, vUv.y * Z_SCALE + 0.375);

    // Layer 1 + Layer 2 offset by half-tile — швы одного перекрыты центром другого
    vec4 c1 = sampleLayer(fract(wp),               base, cell);
    vec4 c2 = sampleLayer(fract(wp + vec2(0.5, 0.0)), base, cell);

    vec4 c = max(c1, c2);
    gl_FragColor = c * 0.5;
}
`,
});

// Called from WaterEffectsView every frame
export const updateCausticsFrame = (t) => {
    causticsMaterial.uniforms.uFrame.value = Math.floor(t * 12) % 60;
};

// ── Bottom geometry (subdivided for vertex displacement) ─────────────────────
export const bottomGeo = new THREE.PlaneGeometry(WATER_ROW_WIDTH, 1, 40, 2);

// ── Bottom material — sandy floor with fake refraction via vertex displacement
export const bottomMaterial = new THREE.ShaderMaterial({
    uniforms: {
        uTime: { value: 0 },
    },

    vertexShader: /* glsl */`
uniform float uTime;
varying vec3  vWorldPos;
varying float vDisplace;

void main() {
    vec3 pos = position;

    // Compute undisplaced world position (instancing-aware)
    #ifdef USE_INSTANCING
    vec4 world = instanceMatrix * vec4(pos, 1.0);
    #else
    vec4 world = modelMatrix * vec4(pos, 1.0);
    #endif

    float d = sin(world.x * 2.4 + uTime * 0.75) * 0.016
            + sin(world.x * 0.9 - world.z * 1.5 + uTime * 0.55) * 0.012
            + sin(world.z * 3.1 + uTime * 0.95) * 0.008;

    pos.y    += d;
    vDisplace = d;
    vWorldPos = world.xyz;

    // Project displaced vertex through the same instance transform
    #ifdef USE_INSTANCING
    gl_Position = projectionMatrix * viewMatrix * instanceMatrix * vec4(pos, 1.0);
    #else
    gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
    #endif
}
`,

    fragmentShader: /* glsl */`
varying vec3  vWorldPos;
varying float vDisplace;

void main() {
    vec3 sand  = vec3(0.96, 0.86, 0.62);
    vec3 sand2 = vec3(1.00, 0.94, 0.74);
    float p    = sin(vWorldPos.x * 3.1) * sin(vWorldPos.z * 2.7) * 0.5 + 0.5;
    vec3 col   = mix(sand, sand2, p * 0.4);
    col *= clamp(1.0 + vDisplace * 10.0, 0.78, 1.22);
    gl_FragColor = vec4(col, 1.0);
}
`,
});
