import { useProgress } from "@react-three/drei";
import { useState, useEffect } from "react";
import { SoundManager } from "./Effects/SoundManager";
import { useGameStore } from "./Logic/store";
import BottomNavBar from "./BottomNavBar";
import { F_TITLE, F_UI, C_BG, C_NAVY_DARK, C_OG1, C_SHADOW, OG_GRAD } from "./UI/uiTheme";

const FAQ_CARD_BG   = '#252B3D';
const FAQ_ITEM_BG   = '#1E2333';
const FAQ_BORDER    = 'rgba(255,255,255,0.07)';

// ── FAQ данные ────────────────────────────────────────────────────────────────
const FAQ_ITEMS = [
    {
        q: 'Как играть?',
        a: 'Управляйте персонажем и продвигайтесь вперед, избегая препятствий и опасностей.\n\nЧем дальше вы продвигаетесь в забеге, тем больше очков получаете. Итоговое количество очков за забег определяет ваше место в таблице лидеров.\n\nСоревнуйтесь с другими участниками, улучшайте свой результат, поднимайтесь в лидерборде и получайте призы.',
    },
    {
        q: 'Как рассчитываются призы?',
        a: 'Призы получают 10 лучших игроков в лидерборде по окончанию события 01.05.2026.\nРейтинг формируется по лучшему результату забега игроков.\n\nПризы:\n1 место — Sport Gloves | Bronze Morph\n2 место — USP-S | The Traitor\n3–5 место — MP7 | Bloodsport\n6–10 место — AK-47 | Searing Rage\n11–15 место — Промокод на 5$',
    },
    {
        q: 'Медаль MVP',
        a: 'Во время забега по карте разбросаны фрагменты медали MVP. Собирайте их, чтобы получать мощные бустеры.\n\nКак только вы соберёте все фрагменты, активируется случайный бустер, который поможет продвинуться дальше и заработать больше очков.\n\nКакие бывают бусты:\n\nСлоу Мо: Все объекты (гранаты, брёвна, лодки) временно замедляются, давая вам больше времени на реакцию.\n\nДвойные Очки: Каждое движение приносит в 2 раза больше очков в течение ограниченного времени.\n\nЩит: Позволяет столкнуться с препятствиями несколько раз без поражения (включая гранаты и падение в воду).\n\nСобирайте фрагменты, получайте бустеры, и устанавливайте новые рекорды!',
    },
];

// ── Шеврон открытия/закрытия ──────────────────────────────────────────────────
function Chevron({ isOpen }) {
    return (
        <svg
            width="20" height="20" viewBox="0 0 20 20" fill="none"
            style={{
                flexShrink: 0,
                transition: 'transform 0.22s',
                transform: isOpen ? 'rotate(180deg)' : 'none',
            }}
        >
            <path d="M5 7.5L10 12.5L15 7.5" stroke="rgba(255,255,255,0.55)" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
        </svg>
    );
}

// ── FAQ экран ─────────────────────────────────────────────────────────────────
function FaqScreen() {
    const [openIdx, setOpenIdx] = useState(0);

    return (
        <div style={{
            position: 'absolute', inset: 0,
            display: 'flex', flexDirection: 'column', alignItems: 'center',
            paddingTop: 'max(env(safe-area-inset-top, 0px), 16px)',
            paddingBottom: 'calc(96px + env(safe-area-inset-bottom, 0px))',
            paddingLeft: 18, paddingRight: 18,
            overflowX: 'hidden',
        }}>
            {/* Карточка */}
            <div style={{
                width: '100%',
                maxWidth: 420,
                flex: 1,
                minHeight: 0,
                background: FAQ_CARD_BG,
                border: `1.5px solid ${FAQ_BORDER}`,
                borderRadius: 16,
                display: 'flex', flexDirection: 'column',
                overflow: 'hidden',
            }}>
                {/* Заголовок карточки */}
                <div style={{
                    padding: '18px 20px 14px',
                    fontFamily: F_TITLE,
                    fontSize: 'clamp(16px, 5vw, 20px)',
                    fontWeight: 700,
                    color: '#fff',
                    letterSpacing: 2,
                    textAlign: 'center',
                    borderBottom: `1px solid ${FAQ_BORDER}`,
                    flexShrink: 0,
                }}>RULES</div>

                {/* Список — скроллится */}
                <div style={{
                    overflowY: 'auto',
                    WebkitOverflowScrolling: 'touch',
                    flex: 1,
                    padding: '12px 14px',
                    display: 'flex', flexDirection: 'column', gap: 10,
                }}>
                    {FAQ_ITEMS.map((item, i) => {
                        const isOpen = openIdx === i;
                        return (
                            <div key={i} style={{
                                background: FAQ_ITEM_BG,
                                border: `1px solid ${FAQ_BORDER}`,
                                borderRadius: 12,
                                overflow: 'hidden',
                            }}>
                                {/* Заголовок строки */}
                                <button
                                    onPointerDown={() => setOpenIdx(isOpen ? -1 : i)}
                                    style={{
                                        background: 'none', border: 'none', cursor: 'pointer',
                                        display: 'flex', alignItems: 'center',
                                        justifyContent: 'space-between', gap: 12,
                                        padding: '14px 16px', width: '100%',
                                        WebkitTapHighlightColor: 'transparent',
                                    }}
                                >
                                    <span style={{
                                        fontFamily: F_UI,
                                        fontSize: 'clamp(12px, 3.5vw, 14px)',
                                        fontWeight: 700,
                                        color: '#fefefe',
                                        textAlign: 'left',
                                        flex: 1,
                                    }}>{item.q}</span>
                                    <Chevron isOpen={isOpen} />
                                </button>

                                {/* Раскрытый текст */}
                                {isOpen && (
                                    <div style={{
                                        padding: '0 16px 16px',
                                        fontFamily: F_UI,
                                        fontSize: 'clamp(11px, 2.8vw, 13px)',
                                        fontWeight: 400,
                                        color: 'rgba(255,255,255,0.75)',
                                        lineHeight: 1.7,
                                        whiteSpace: 'pre-line',
                                    }}>{item.a}</div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}


// ── Лого (общее для лобби и FAQ) ──────────────────────────────────────────────
function Logo() {
    return (
        <img
            src="/images/MainLogo.png"
            alt="Chickpoint Rush"
            style={{
                width: 'clamp(200px, 80vw, 420px)',
                height: 'auto',
                display: 'block',
                filter: 'drop-shadow(0 4px 16px rgba(0,0,0,0.5))',
            }}
        />
    );
}

// ── Главный компонент ─────────────────────────────────────────────────────────
export default function Loader() {
    const { active, progress } = useProgress();
    const [isReady,   setIsReady]   = useState(false);
    const [navTab,    setNavTab]    = useState('play');
    const [showFaq,   setShowFaq]   = useState(false);
    const isStarted  = useGameStore(s => s.isStarted);
    const setStarted = useGameStore(s => s.setStarted);

    useEffect(() => {
        if (progress >= 100 && !active) {
            const t = setTimeout(() => setIsReady(true), 500);
            return () => clearTimeout(t);
        }
    }, [progress, active]);

    const handleStart = () => {
        if (!isReady) return;
        const s = useGameStore.getState();
        s.closeChestAll?.();
        s.closeLeaderboardAll?.();
        s.closeWardrobeAll?.();
        SoundManager.unlock();
        SoundManager.fadeInGlobal(1500);
        SoundManager.startAmbient();
        setStarted();
    };

    if (isStarted) return null;

    const navH = 'calc(76px + env(safe-area-inset-bottom, 0px))';

    return (
        <>
        <div style={{
            position: 'fixed', inset: 0, zIndex: 200,
            background: isReady ? 'transparent' : C_BG,
            transition: 'background 0.9s ease',
            overflow: 'hidden',
        }}>

            {/* ── Экран загрузки ── */}
            {!isReady && (
                <div style={{
                    position: 'absolute', inset: 0,
                    display: 'flex', flexDirection: 'column',
                    alignItems: 'center', justifyContent: 'space-between',
                    paddingTop: 'max(env(safe-area-inset-top, 0px), 48px)',
                    paddingBottom: 'calc(84px + env(safe-area-inset-bottom, 0px))',
                }}>
                    <Logo />

                    <div style={{ width: 'min(55%, 200px)' }}>
                        <div style={{ height: 3, background: 'rgba(255,255,255,0.08)', borderRadius: 2 }}>
                            <div style={{
                                height: '100%', background: C_OG1,
                                width: `${progress}%`, transition: 'width 0.3s', borderRadius: 2,
                            }} />
                        </div>
                        <p style={{
                            fontFamily: F_UI, fontSize: 9, marginTop: 10,
                            letterSpacing: 3, color: 'rgba(255,255,255,0.3)', textAlign: 'center',
                        }}>LOADING {Math.round(progress)}%</p>
                    </div>
                </div>
            )}

            {/* ── Главный экран (лобби) — только когда play таб активен ── */}
            {isReady && navTab === 'play' && !showFaq && (
                <div
                    onPointerDown={handleStart}
                    style={{
                        position: 'absolute', inset: 0,
                        display: 'flex', flexDirection: 'column',
                        alignItems: 'center', justifyContent: 'space-between',
                        paddingBottom: `calc(${navH} + 32px)`,
                        paddingTop: 'max(env(safe-area-inset-top, 0px), 48px)',
                        cursor: 'pointer',
                        WebkitTapHighlightColor: 'transparent',
                    }}
                >
                    <Logo />

                    {/* TAP TO PLAY + Hand */}
                    <div style={{
                        display: 'flex', flexDirection: 'column',
                        alignItems: 'center', gap: 32,
                        marginBottom: 32,
                        pointerEvents: 'none',
                    }}>
                        <img
                            src="/images/Hand.svg"
                            alt="" 
                            style={{
                                width: 'clamp(130px, 16vw, 150px)',
                                animation: 'lPulse 2.4s ease-in-out infinite',
                                animationDelay: '0.15s',
                                alignSelf: 'flex-end',
                                marginRight: '40px',
                            }}
                        />
                        <div style={{
                            fontFamily: F_TITLE,
                            fontSize: 'clamp(40px, 5.5vw, 40px)',
                            fontWeight: 700,
                            color: '#fff',
                            letterSpacing: '0.08em',
                            textShadow: '0 8px 0px #181a27',
                            animation: 'lPulse 2.4s ease-in-out infinite',
                        }}>
                            TAP TO PLAY
                        </div>
                    </div>
                </div>
            )}

            {/* ── FAQ экран ── */}
            {isReady && showFaq && <FaqScreen />}

            <style>{`
                @keyframes lPulse {
                    0%,100% { transform: scale(1); }
                    50%      { transform: scale(1.025); }
                }
            `}</style>
        </div>
        <BottomNavBar
            onPlay={handleStart}
            onFaq={(open) => setShowFaq(open)}
            onTabChange={(id) => setNavTab(id)}
            playEnabled={isReady}
            initialTab="play"
            zIndex={4000}
        />
        </>
    );
}
