import { Howl, Howler } from 'howler';

const SOUNDS_CONFIG = {
    jump:           { src: ['/sound/chicken_panic_04.mp3'], volume: 0.40 },
    land:           { src: ['/sound/land3.mp3'], volume: 0.40 },
    hit:            { src: ['/sound/cardboard_pizzabox_impact2.wav'], volume: 0.55 },
    molotov:        { src: ['/sound/molotov_detonate_1.wav'], volume: 0.60 },
    flash:          { src: ['/sound/flashbang_explode2.wav'], volume: 0.60 },
    bang:           { src: ['/sound/explosion_ring.wav'], volume: 0.50 },
    drown:          { src: ['/sound/pl_wade2.wav'], volume: 0.65 },
    ambient:        { src: ['/sound/wind_low_amb.wav'], volume: 0.40, loop: true },
    death:          { src: ['/sound/chicken_death_01.mp3'], volume: 0.60 },
    boat:           { src: ['/sound/water_splash_03.wav'], volume: 0.50 },
    // Монетки
    coin:           { src: ['/sound/timer_bell.wav'], volume: 0.50 },
    coinRed:        { src: ['/sound/pointscored.wav'], volume: 0.55 },
    // Медали
    medalCollect:   { src: ['/sound/bell_normal.wav'], volume: 0.55 },
    medalPowerup:   { src: ['/sound/bell_impact.wav'], volume: 0.65 },
    // Граната HE
    grenadeExplosion: { src: ['/sound/hegrenade_detonate_03.wav'], volume: 0.65 },
    bombInitiate:   { src: ['/sound/c4_initiate.wav'], volume: 0.60 },
    bombBeep:       { src: ['/sound/c4_beep2.wav'], volume: 0.50 },
    explosion:      { src: ['/sound/c4_explode1.wav'], volume: 0.70 },
    bombDisarm:     { src: ['/sound/c4_disarmfinish.wav'], volume: 0.55 },
    // Снайпер
    sniperZoom:     { src: ['/sound/zoom.wav'], volume: 0.50 },
    sniperShot:     { src: ['/sound/awp_distant.wav'], volume: 0.70 },
    sniperZoomOut:  { src: ['/sound/awp_zoom_out.wav'], volume: 0.50 },
    // Рекорд
    highscore:      { src: ['/sound/highscore.wav'], volume: 0.65 },
    score100:       { src: ['/sound/score100.wav'],       volume: 0.65 },
    xpMilestone:    { src: ['/sound/xp_milestone_01.wav'], volume: 0.65 },
    xpLevelup:      { src: ['/sound/xp_levelup.wav'],      volume: 0.65 },
    // Смерть от снайпера
    deathSniper:    { src: ['/sound/chicken_death_02.mp3'], volume: 0.60 },
    // Idle / panic
    chickenIdle:    { src: ['/sound/chicken_idle_01.mp3'], volume: 0.40 },
    chickenPanic:   { src: ['/sound/chicken_panic_01.mp3'], volume: 0.50 },
    // Вода
    waterAmbient:   { src: ['/sound/riverlap_07.wav'], volume: 0, loop: true },
};

class SoundManagerInstance {
    constructor() {
        this.sounds = {};
        Howler.volume(0);
        Object.entries(SOUNDS_CONFIG).forEach(([key, config]) => {
            this.sounds[key] = new Howl({ ...config, preload: true });
        });
    }

    unlock() {
        if (Howler.ctx && Howler.ctx.state !== 'running') {
            Howler.ctx.resume();
        }
        const context = Howler.ctx;
        if (context) {
            const buffer = context.createBuffer(1, 1, 22050);
            const source = context.createBufferSource();
            source.buffer = buffer;
            source.connect(context.destination);
            source.start(0);
            source.onended = () => source.disconnect();
        }
    }

    fadeInGlobal(duration = 1500) {
        const start = performance.now();
        const tick = () => {
            const t = Math.min((performance.now() - start) / duration, 1);
            Howler.volume(t);
            if (t < 1) requestAnimationFrame(tick);
        };
        requestAnimationFrame(tick);
    }

    startAmbient() {
        const ambient = this.sounds.ambient;
        if (!ambient || ambient.playing()) return;
        ambient.play();
    }

    playCoin(isRed = false) {
        if (isRed) {
            this.sounds.coinRed?.play();
        } else {
            const s = this.sounds.coin;
            if (!s) return;
            s.rate(0.85 + Math.random() * 0.3); // питч 0.85..1.15
            s.play();
        }
    }

    playSniperZoom() {
        const s = this.sounds.sniperZoom;
        if (!s) return;
        s.play();
        setTimeout(() => { if (s) s.play(); }, 200);
    }

    play(name, randomizePitch = true) {
        const sound = this.sounds[name];
        if (!sound) return;
        if (randomizePitch) sound.rate(0.9 + Math.random() * 0.2);
        sound.play();
    }

    stop(name) {
        this.sounds[name]?.stop();
    }

    setWaterAmbient(volume) {
        const s = this.sounds.waterAmbient;
        if (!s) return;
        // Троттл: не дёргаем Web Audio API если значение почти не изменилось
        if (Math.abs(volume - (this._waterVol ?? -1)) < 0.03) return;
        this._waterVol = volume;
        if (volume > 0.01) {
            s.volume(volume);
            if (!s.playing()) s.play();
        } else {
            if (s.playing()) s.pause();
        }
    }

    setMuted(muted) {
        Howler.mute(muted);
    }

    playDeafening() {
        const id = this.sounds.bang.play();
        this.sounds.bang.fade(0.4, 0, 3000, id);
    }
}

export const SoundManager = new SoundManagerInstance();