import gsap from "gsap";
import { useLayoutEffect, useMemo, useRef } from "react";
import * as THREE from "three";

const FEATHER_COUNT = 28;

// Геометрии с фиксированными размерами — не пересоздаются при каждом рендере
const featherSizes = Array.from({ length: FEATHER_COUNT }, () => ({
    w: 0.055 + Math.random() * 0.045,
    h: 0.16  + Math.random() * 0.16,
}));

export default function Feathers({ position }) {
    const groupRef = useRef();

    // Случайные параметры разлёта — фиксированы на весь lifetime компонента
    const particleData = useMemo(() =>
        Array.from({ length: FEATHER_COUNT }, () => ({
            angle:   Math.random() * Math.PI * 2,
            radius:  0.4  + Math.random() * 2.2,
            yPeak:   0.8  + Math.random() * 2.0,
            fallDur: 1.4  + Math.random() * 2.0,
            delay:   Math.random() * 0.3,
            rx: (Math.random() - 0.5) * Math.PI * 6,
            ry:  Math.random()        * Math.PI * 8,
            rz: (Math.random() - 0.5) * Math.PI * 5,
        })), []);

    useLayoutEffect(() => {
        const group = groupRef.current;
        if (!group) return;

        group.children.forEach((mesh, i) => {
            const d = particleData[i];
            const tx = Math.cos(d.angle) * d.radius;
            const tz = Math.sin(d.angle) * d.radius;

            gsap.killTweensOf(mesh.position);
            gsap.killTweensOf(mesh.rotation);
            gsap.killTweensOf(mesh.material);

            gsap.set(mesh.position, { x: 0, y: 0, z: 0 });
            gsap.set(mesh.rotation, { x: 0, y: 0, z: 0 });
            gsap.set(mesh.material, { opacity: 0.9 });

            gsap.to(mesh.position, {
                x: tx * 0.35, y: d.yPeak, z: tz * 0.35,
                duration: 0.28, ease: "power3.out", delay: d.delay,
            });
            gsap.to(mesh.position, {
                x: tx, y: -0.3, z: tz,
                duration: d.fallDur, ease: "power1.in", delay: d.delay + 0.28,
            });
            gsap.to(mesh.rotation, {
                x: d.rx, y: d.ry, z: d.rz,
                duration: d.fallDur + 0.3, ease: "none", delay: d.delay,
            });
            gsap.to(mesh.material, {
                opacity: 0,
                duration: 0.7, ease: "power1.in",
                delay: d.delay + 0.28 + Math.max(0, d.fallDur - 0.7),
            });
        });

        return () => {
            group.children.forEach(mesh => {
                gsap.killTweensOf(mesh.position);
                gsap.killTweensOf(mesh.rotation);
                gsap.killTweensOf(mesh.material);
            });
        };
    }, [position[0], position[2], particleData]);

    return (
        <group ref={groupRef} position={position}>
            {featherSizes.map(({ w, h }, i) => (
                <mesh key={i}>
                    <planeGeometry args={[w, h]} />
                    <meshStandardMaterial
                        color="#f0efe8"
                        transparent
                        opacity={0.9}
                        roughness={1}
                        metalness={0}
                        side={THREE.DoubleSide}
                        depthWrite={false}
                    />
                </mesh>
            ))}
        </group>
    );
}
