import { useGLTF } from '@react-three/drei';
import { useEffect, useState } from 'react';
import * as THREE from 'three';
import { sharedAtlasMaterial } from './sharedMaterial';

// [z, rotY] — rotY=π смотрит в сторону +Z (суша/дорога), rotY=0 в сторону -Z (вода/низ)
const DIVIDERS = [
    [-10, Math.PI], // между Z=-9 (дорога) и Z=-10 (трава низ)
    [-13, Math.PI], // между Z=-12 (трава низ) и Z=-13 (вода низ)
];
const DIVIDER_Y = -1.75;
const COUNT     = DIVIDERS.length;

const temp = new THREE.Object3D();

export default function StartDivider() {
    const { nodes } = useGLTF('/models/waterside.glb');
    const [mesh, setMesh] = useState(null);

    useEffect(() => {
        const geo = Object.values(nodes).find(n => n.isMesh)?.geometry;
        if (!geo) return;

        const b = new THREE.BatchedMesh(
            COUNT,
            geo.attributes.position.count,
            geo.index ? geo.index.count : geo.attributes.position.count,
            sharedAtlasMaterial
        );
        b.frustumCulled          = false;
        b.perObjectFrustumCulled = false;

        const geoId = b.addGeometry(geo);

        for (const [z, rotY] of DIVIDERS) {
            const id = b.addInstance(geoId);
            temp.position.set(0, DIVIDER_Y, z);
            temp.rotation.set(0, rotY, 0);
            temp.scale.set(1, 1, 1);
            temp.updateMatrix();
            b.setMatrixAt(id, temp.matrix);
            b.setVisibleAt(id, true);
        }

        setMesh(b);
        return () => { b.dispose(); setMesh(null); };
    }, [nodes]);

    if (!mesh) return null;
    return <primitive object={mesh} />;
}
