// ── Прогрессия сложности ─────────────────────────────────────────────────────
// Вероятности рядов плавно меняются от START (z=FOREST_START_ROW) до END (z=DIFF_Z_MAX).
// Порог r > probX означает тип X; P(X) = prevThreshold - thisThreshold.
//   Начало:  Forest 50%, Road 20%, Water  5%, Grass 25%
//   Конец:   Forest 25%, Road 35%, Water 30%, Grass 10%
export const DIFF_Z_MAX              = 500;   // z, при котором достигается макс. сложность
//   Начало:  Grass 45%, Forest 30%, Road 15%, Water 10%
//   Конец:   Forest 20%, Road 40%, Water 30%, Grass 10%
export const DIFF_PROB_FOREST_START  = 0.70;  // начало: P(forest)=30%
export const DIFF_PROB_FOREST_END    = 0.80;  // конец:  P(forest)=20%
export const DIFF_PROB_ROAD_START    = 0.55;  // начало: P(road)=15%
export const DIFF_PROB_ROAD_END      = 0.40;  // конец:  P(road)=40%
export const DIFF_PROB_WATER_START   = 0.45;  // начало: P(water)=10%, P(grass)=45%
export const DIFF_PROB_WATER_END     = 0.10;  // конец:  P(water)=30%, P(grass)=10%

