import { useGLTF } from '@react-three/drei';
import { sharedSkinAtlasMaterial } from '../View/sharedMaterial';

export default function ChickenSkin({ modelName, material, parts, ...props }) {
    const { nodes } = useGLTF('/models/chickens.glb');

    if (parts) {
        return (
            <group {...props} dispose={null}>
                {parts.flatMap(({ names, material: partMat }) =>
                    names.map(name => {
                        const geo = nodes[name]?.geometry ?? null;
                        return geo ? <mesh key={name} geometry={geo} material={partMat} /> : null;
                    })
                )}
            </group>
        );
    }

    const geometry = nodes[modelName]?.geometry ?? null;
    if (!geometry) return null;
    return (
        <group {...props} dispose={null}>
            <mesh geometry={geometry} material={material ?? sharedSkinAtlasMaterial} />
        </group>
    );
}

useGLTF.preload('/models/chickens.glb');
