import * as THREE from 'three';

// ── Dissolve uniform (shared with atlas material) ─────────────────────────────
const _transpPts = [];
for (let i = 0; i < 8; i++) _transpPts.push(new THREE.Vector4(0, 0, 1.5, 0));
export const transpPointsUniform = { value: _transpPts };

// ── Shadow material (shadow.png — запечённая тень под пропсами) ───────────────
const _shadowTexture = new THREE.TextureLoader().load('/images/shadow.png');
_shadowTexture.colorSpace = THREE.SRGBColorSpace;
_shadowTexture.flipY      = false;

export const sharedShadowMaterial = new THREE.MeshBasicMaterial({
    map:          _shadowTexture,
    transparent:  true,
    depthWrite:   false,
    alphaTest:    0.33,
    opacity:      0.45,
    stencilWrite: true,
    stencilFunc:  THREE.EqualStencilFunc,
    stencilRef:   0,
    stencilFail:  THREE.KeepStencilOp,
    stencilZFail: THREE.KeepStencilOp,
    stencilZPass: THREE.IncrementWrapStencilOp,
});

// ── Atlas material (tile.glb — UV-mapped to textureAtlas.png) ─────────────────
const _loader = new THREE.TextureLoader();
export const atlasTexture = _loader.load('/images/textureAtlas.png');
const _atlasTexture = atlasTexture;
_atlasTexture.colorSpace = THREE.SRGBColorSpace;
_atlasTexture.flipY      = false;
_atlasTexture.minFilter  = THREE.LinearMipmapLinearFilter;
_atlasTexture.magFilter  = THREE.LinearFilter;

export const sharedAtlasMaterial = new THREE.MeshStandardMaterial({
    map:             _atlasTexture,
    vertexColors:    false,
    flatShading:     false,
    roughness:       0.82,
    metalness:       0.0,
    polygonOffset:   true,
    polygonOffsetFactor: -1,
    polygonOffsetUnits:  -1,
});

sharedAtlasMaterial.onBeforeCompile = (shader) => {
    shader.uniforms.uTranspPoints = transpPointsUniform;

    // ── Vertex: vWorldPos ────────────────────────────────────────────────────
    shader.vertexShader = shader.vertexShader.replace(
        'void main() {',
        `varying vec3 vWorldPos;\nvoid main() {`
    );
    shader.vertexShader = shader.vertexShader.replace(
        '#include <fog_vertex>',
        `#include <fog_vertex>
        #ifdef USE_BATCHING
            vWorldPos = (modelMatrix * batchingMatrix * vec4(transformed, 1.0)).xyz;
        #else
            vWorldPos = (modelMatrix * vec4(transformed, 1.0)).xyz;
        #endif`
    );

    // ── Fragment: dissolve near coins/medals ─────────────────────────────────
    shader.fragmentShader = shader.fragmentShader.replace(
        'void main() {',
        `varying vec3 vWorldPos;\nuniform vec4 uTranspPoints[8];\nvoid main() {`
    );
    shader.fragmentShader = shader.fragmentShader.replace(
        '#include <dithering_fragment>',
        `#include <dithering_fragment>
        const float _BAYERA[16] = float[16](
             0.0,  8.0,  2.0, 10.0,
            12.0,  4.0, 14.0,  6.0,
             3.0, 11.0,  1.0,  9.0,
            15.0,  7.0, 13.0,  5.0);
        vec3 _camFwdA = normalize(vec3(viewMatrix[0][2], viewMatrix[1][2], viewMatrix[2][2]));
        float _dissolveA = 0.0;
        for (int i = 0; i < 8; i++) {
            if (uTranspPoints[i].w < 0.5) continue;
            vec3 _coinWA = vec3(uTranspPoints[i].x, 0.5, uTranspPoints[i].y);
            vec3 _offA = vWorldPos - _coinWA;
            float _alongA = dot(_offA, _camFwdA);
            if (_alongA > 0.0) {
                float _perpA = length(_offA - _alongA * _camFwdA);
                _dissolveA = max(_dissolveA, 1.0 - smoothstep(0.0, uTranspPoints[i].z, _perpA));
            }
        }
        if (_dissolveA > 0.01) {
            int _biA = int(mod(gl_FragCoord.x, 4.0)) + int(mod(gl_FragCoord.y, 4.0)) * 4;
            if (_BAYERA[_biA] / 16.0 < _dissolveA * 0.88) discard;
        }`
    );
};

sharedAtlasMaterial.customProgramCacheKey = () => 'atlas_dissolve_v6';

// ── Coin material (atlas + emissive glow from texture colour) ─────────────────
export const coinAtlasMaterial = new THREE.MeshStandardMaterial({
    map:              _atlasTexture,
    emissiveMap:      _atlasTexture,
    emissive:         new THREE.Color(1, 1, 1),
    emissiveIntensity: 0.5,
    vertexColors:     false,
    roughness:        0.5,
    metalness:        0.15,
    polygonOffset:    true,
    polygonOffsetFactor: -1,
    polygonOffsetUnits:  -1,
});

// ── Grenade material (metallic + specular highlight) ──────────────────────────
export const sharedGrenadeMaterial = new THREE.MeshStandardMaterial({
    vertexColors: true,
    roughness:    0.52,
    metalness:    0.0,
});

// ── Skin-atlas material (textureSkinAtlas.png — for CS16, Moorhuhn, Rubber) ────
const _skinTexture = new THREE.TextureLoader().load('/images/textureSkinAtlas.png');
_skinTexture.colorSpace = THREE.SRGBColorSpace;
_skinTexture.flipY      = false;
_skinTexture.minFilter  = THREE.LinearMipmapLinearFilter;
_skinTexture.magFilter  = THREE.LinearFilter;

export const skinAtlasTexture = _skinTexture;

const _skinMat = new THREE.MeshStandardMaterial({
    map:          _skinTexture,
    vertexColors: true,
    roughness:    0.82,
    metalness:    0.0,
});
_skinMat.color.setScalar(2.8);
export const sharedSkinAtlasMaterial = _skinMat;

// ── Chicken material (vertex colours only — no atlas multiply) ────────────────
export const sharedChickenMaterial = new THREE.MeshStandardMaterial({
    vertexColors: true,
    flatShading:  false,
    roughness:    0.82,
    metalness:    0.0,
});

// ── Aurora atlas material (textureAtlasAurora.png — for Aurora skin overlays) ─
const _auroraTexture = new THREE.TextureLoader().load('/images/textureAtlasAurora.png');
_auroraTexture.colorSpace = THREE.SRGBColorSpace;
_auroraTexture.flipY      = false;
_auroraTexture.minFilter  = THREE.LinearMipmapLinearFilter;
_auroraTexture.magFilter  = THREE.LinearFilter;

export const auroraAtlasTexture = _auroraTexture;


