import { useEffect, useState } from 'react';
import { useGameStore } from './Logic/store';
import { SoundManager } from './Effects/SoundManager';
import MedalReveal from './MedalReveal';
import { F_TITLE, OG_GRAD } from './UI/uiTheme';
import CloseIcon from './UI/CloseIcon';

const CARD_BG   = '#252B3D';
const CARD_BORDER = 'rgba(255,255,255,0.08)';

// ── SVG Icons ────────────────────────────────────────────────────────────────
const IconHome = () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M3 11L12 4l9 7" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M5 9.5V20h4.5v-5h5v5H19V9.5" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
);

const IconVolumeOn = () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M6 9H3v6h3l5 4V5L6 9Z" stroke="white" strokeWidth="2" strokeLinejoin="round"/>
        <path d="M17 7c1.5 1.4 2.5 3.1 2.5 5s-1 3.6-2.5 5" stroke="white" strokeWidth="2" strokeLinecap="round"/>
        <path d="M14 9.5c.8.7 1.2 1.6 1.2 2.5s-.4 1.8-1.2 2.5" stroke="white" strokeWidth="2" strokeLinecap="round"/>
    </svg>
);

const IconVolumeOff = () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M6 9H3v6h3l5 4V5L6 9Z" stroke="white" strokeWidth="2" strokeLinejoin="round"/>
        <path d="M18 9l-4 6M14 9l4 6" stroke="white" strokeWidth="2" strokeLinecap="round"/>
    </svg>
);


export default function PauseMenu() {
    const isPaused     = useGameStore(s => s.isPaused);
    const togglePause  = useGameStore(s => s.togglePause);
    const soundEnabled = useGameStore(s => s.soundEnabled);
    const toggleSound  = useGameStore(s => s.toggleSound);
    const isDead       = useGameStore(s => s.isDead);
    const isStarted    = useGameStore(s => s.isStarted);
    const goToLobby    = useGameStore(s => s.goToLobby);

    const [medalOpen, setMedalOpen] = useState(false);
    const [counting, setCounting]   = useState(null); // null | 3 | 2 | 1

    useEffect(() => {
        if (counting === null) return;
        if (counting === 0) { togglePause(); setCounting(null); return; }
        const t = setTimeout(() => setCounting(c => c - 1), 667);
        return () => clearTimeout(t);
    }, [counting]);

    useEffect(() => {
        if (!isPaused) setCounting(null);
    }, [isPaused]);

    useEffect(() => {
        SoundManager.setMuted(!soundEnabled);
    }, [soundEnabled]);

    useEffect(() => {
        const onKey = (e) => { if (e.key === 'Escape') togglePause(); };
        window.addEventListener('keydown', onKey);
        return () => window.removeEventListener('keydown', onKey);
    }, [togglePause]);

    return (
        <>
            {!isDead && (
                <button
                    onPointerDown={
                        counting !== null       ? () => setCounting(null)
                        : isPaused && isStarted ? () => setCounting(3)
                        : togglePause
                    }
                    style={{
                        position: 'fixed',
                        top: 'min(5vh, 28px)',
                        right: 'min(5vw, 20px)',
                        zIndex: 3000,
                        background: 'none',
                        border: 'none',
                        padding: 0,
                        cursor: 'pointer',
                        WebkitTapHighlightColor: 'transparent',
                    }}
                >
                    <img src="/images/Settings.svg" width="48" height="52" alt="Settings" style={{ display: 'block' }}/>
                </button>
            )}

            {isPaused && counting === null && (
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 2500,
                    background: 'rgba(10,5,20,0.72)',
                    backdropFilter: 'blur(10px)',
                    WebkitBackdropFilter: 'blur(10px)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    animation: 'menuFadeIn 0.2s ease-out',
                }}>
                    <div style={{
                        width: 'min(320px, 88vw)',
                        padding: '24px 20px 20px',
                        background: CARD_BG,
                        border: `1.5px solid ${CARD_BORDER}`,
                        borderRadius: '20px',
                        display: 'flex', flexDirection: 'column',
                        gap: 16,
                        position: 'relative',
                    }}>
                        {/* Close button */}
                        <div
                            onPointerDown={() => isStarted ? setCounting(3) : togglePause()}
                            style={{
                                position: 'absolute', top: 12, right: 12,
                                cursor: 'pointer',
                                WebkitTapHighlightColor: 'transparent',
                            }}
                        ><CloseIcon size={28} /></div>

                        {/* Title */}
                        <div style={{
                            fontFamily: F_TITLE,
                            fontWeight: 700,
                            fontSize: 'clamp(20px, 6vw, 26px)',
                            color: '#fff',
                            textAlign: 'center',
                            letterSpacing: 3,
                            textShadow: '0 4px 0px #181a27',
                        }}>ПАУЗА</div>

                        {/* Continue */}
                        <button
                            onPointerDown={() => isStarted ? setCounting(3) : togglePause()}
                            style={{
                                width: '100%',
                                height: 48,
                                background: OG_GRAD,
                                border: 'none',
                                borderRadius: 12,
                                cursor: 'pointer',
                                fontFamily: F_TITLE,
                                fontWeight: 700,
                                fontSize: 24,
                                color: '#fff',
                                letterSpacing: 3,
                                textShadow: '0 3px 0px #A75600',
                                WebkitTapHighlightColor: 'transparent',
                                boxShadow: 'inset 0 -3px 0 rgba(0,0,0,0.25), inset 0 2px 0 rgba(255,255,255,0.2)',
                            }}
                        >ПРОДОЛЖИТЬ</button>

                        {/* Icon buttons */}
                        <div style={{ display: 'flex', gap: 12 }}>
                            <button
                                onPointerDown={goToLobby}
                                style={{
                                    flex: 1, height: 52, borderRadius: 12,
                                    background: 'rgba(255,255,255,0.07)',
                                    border: `1px solid ${CARD_BORDER}`,
                                    cursor: 'pointer', display: 'flex',
                                    alignItems: 'center', justifyContent: 'center',
                                    WebkitTapHighlightColor: 'transparent',
                                }}
                            ><IconHome /></button>
                            <button
                                onPointerDown={toggleSound}
                                style={{
                                    flex: 1, height: 52, borderRadius: 12,
                                    background: 'rgba(255,255,255,0.07)',
                                    border: `1px solid ${CARD_BORDER}`,
                                    cursor: 'pointer', display: 'flex',
                                    alignItems: 'center', justifyContent: 'center',
                                    WebkitTapHighlightColor: 'transparent',
                                }}
                            >{soundEnabled ? <IconVolumeOn /> : <IconVolumeOff />}</button>
                        </div>
                    </div>
                </div>
            )}

            {/* ── Countdown overlay ── */}
            {counting !== null && (
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 2500,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    pointerEvents: 'none',
                }}>
                    <div key={counting} style={{
                        fontFamily: F_TITLE,
                        fontSize: 'clamp(80px, 22vw, 120px)',
                        fontWeight: 700,
                        letterSpacing: 2,
                        background: OG_GRAD,
                        WebkitBackgroundClip: 'text',
                        WebkitTextFillColor: 'transparent',
                        filter: 'drop-shadow(0 4px 16px rgba(0,0,0,0.7))',
                        animation: 'countPop 0.25s cubic-bezier(0.34,1.56,0.64,1) both',
                    }}>
                        {counting}
                    </div>
                </div>
            )}

            {medalOpen && (
                <MedalReveal onClose={() => setMedalOpen(false)} />
            )}

            <style>{`
                @keyframes menuFadeIn {
                    from { opacity: 0; transform: scale(0.96); }
                    to   { opacity: 1; transform: scale(1); }
                }
                @keyframes countPop {
                    from { opacity: 0; transform: scale(0.4); }
                    to   { opacity: 1; transform: scale(1); }
                }
            `}</style>
        </>
    );
}
