import * as THREE from 'three';
import { skinAtlasTexture, auroraAtlasTexture } from '../View/sharedMaterial';

// Общий GLSL-блок деформации — вставляется в оба материала
const DEFORM_DECLARATIONS = `
uniform float uStretch;
uniform float uTwist;
uniform float uBend;
uniform float uBreathe;`;

const DEFORM_CODE = `
// ── STRETCH (volume-preserving) ──────────────────────────────
transformed.y *= uStretch;
float _inv = 1.0 / sqrt(max(abs(uStretch), 0.01));
transformed.xz *= _inv;

// ── TWIST вокруг Y (нарастает с высотой) ─────────────────────
float _ta = transformed.y * uTwist;
float _ts = sin(_ta);
float _tc = cos(_ta);
transformed.xz = mat2(_tc, -_ts, _ts, _tc) * transformed.xz;

// ── BEND вперёд (квадратичная кривая по Z) ───────────────────
float _b = transformed.y * uBend;
transformed.z += _b * abs(_b);

// ── BREATHE (subtle chest rise / fall) ───────────────────────
float _bAmt = sin(uBreathe * 2.5) * 0.5 + 0.5;
float _bW   = smoothstep(0.0, 0.5, transformed.y);
transformed.y  += _bAmt * _bW * 0.035;
transformed.xz *= 1.0 + _bAmt * _bW * 0.01;`;

function injectDeform(shader, uniforms) {
    shader.uniforms.uStretch      = uniforms.uStretch;
    shader.uniforms.uTwist        = uniforms.uTwist;
    shader.uniforms.uBend         = uniforms.uBend;
    shader.uniforms.uBreathe      = uniforms.uBreathe;
    shader.uniforms.uShadowFactor = uniforms.uShadowFactor;
    shader.vertexShader = shader.vertexShader
        .replace('#include <common>',      `#include <common>${DEFORM_DECLARATIONS}`)
        .replace('#include <begin_vertex>', `#include <begin_vertex>${DEFORM_CODE}`);
    shader.fragmentShader = shader.fragmentShader
        .replace('#include <common>', `#include <common>\nuniform float uShadowFactor;`)
        .replace('#include <dithering_fragment>',
            `gl_FragColor.rgb *= mix(1.0, 0.65, uShadowFactor);\n#include <dithering_fragment>`);
}

/**
 * Создаёт основной материал курицы (vertexColors) + uniforms-объект.
 * Возвращает { mat, uniforms }.
 */
export function createChickenDeformMaterial() {
    const uniforms = {
        uStretch:      { value: 1.0 },
        uTwist:        { value: 0.0 },
        uBend:         { value: 0.0 },
        uBreathe:      { value: 0.0 },
        uShadowFactor: { value: 0.0 },
    };

    const mat = new THREE.MeshStandardMaterial({ vertexColors: true, flatShading: false });
    mat.onBeforeCompile = (shader) => injectDeform(shader, uniforms);
    mat.customProgramCacheKey = () => 'chicken_deform_v4';

    return { mat, uniforms };
}

/**
 * Создаёт материал для skin-куриц (CS16, Moorhuhn, Rubber) — textureSkinAtlas, без vertexColors.
 */
export function createSkinDeformMaterial() {
    const uniforms = {
        uStretch:      { value: 1.0 },
        uTwist:        { value: 0.0 },
        uBend:         { value: 0.0 },
        uBreathe:      { value: 0.0 },
        uShadowFactor: { value: 0.0 },
    };
    const mat = new THREE.MeshStandardMaterial({ map: skinAtlasTexture, vertexColors: true, flatShading: false, roughness: 0.82, metalness: 0 });
    mat.color.setScalar(1.8);
    mat.onBeforeCompile = (shader) => injectDeform(shader, uniforms);
    mat.customProgramCacheKey = () => 'skin_deform_v1';
    return { mat, uniforms };
}

/**
 * Создаёт материал для экипированных предметов, разделяющий те же uniforms что
 * и курица — все GSAP-анимации (stretch/twist/bend) автоматически применяются к обоим.
 *
 * @param {string|number} color    - CSS-цвет или hex (напр. '#ff0000' или 0xff0000)
 * @param {object}        uniforms - ссылка на world.deformUniforms курицы (НЕ копия!)
 * @param {object}        opts     - доп. параметры MeshStandardMaterial
 */
export function createItemDeformMaterial(color, uniforms, opts = {}) {
    const mat = new THREE.MeshStandardMaterial({
        color,
        roughness: 0.45,
        metalness: 0.0,
        ...opts,
    });
    // Каждый material получает УНИКАЛЬНЫЙ ключ чтобы Three.js не делил шейдерный кэш
    const colorKey = typeof color === 'string' ? color : color.toString(16);
    mat.onBeforeCompile = (shader) => injectDeform(shader, uniforms);
    mat.customProgramCacheKey = () => `item_deform_${colorKey}`;
    return mat;
}

// ── Gold material (metallic gold + deform) ────────────────────────────────────
// deformUniforms — if passed, the gold parts share the exact same uniform objects
// as the chicken body, so all GSAP deform animations apply to both simultaneously.
export function createGoldDeformMaterial(deformUniforms) {
    const def = (key, val) => deformUniforms?.[key] ?? { value: val };
    const uniforms = {
        uStretch:      def('uStretch',      1.0),
        uTwist:        def('uTwist',        0.0),
        uBend:         def('uBend',         0.0),
        uBreathe:      def('uBreathe',      0.0),
        uShadowFactor: def('uShadowFactor', 0.0),
    };
    const mat = new THREE.MeshStandardMaterial({
        color:     new THREE.Color(1.0, 0.84, 0.0),
        roughness: 0.12,
        metalness: 0.92,
    });
    mat.onBeforeCompile = (shader) => {
        injectDeform(shader, uniforms);
        // Fake gold environment: matcap gradient + Fresnel + specular highlight
        shader.fragmentShader = shader.fragmentShader.replace(
            '#include <dithering_fragment>',
            `// ── Fake gold sheen ─────────────────────────────────────────
            vec3  _gN  = normalize(normal);
            vec3  _gV  = normalize(vViewPosition);
            float _gNV = max(0.0, dot(_gN, _gV));
            // Matcap: view-space normal.y maps bottom→top of environment
            vec3 _gEnv = mix(vec3(0.18, 0.08, 0.0), vec3(1.5, 1.1, 0.1),
                             clamp(_gN.y * 0.5 + 0.5, 0.0, 1.0));
            // Fresnel rim — gold edges glow warm
            float _gFr = pow(1.0 - _gNV, 2.5);
            // Blinn-Phong specular against a fake key light
            vec3  _gL  = normalize(vec3(0.45, 0.85, 0.4));
            float _gSp = pow(max(0.0, dot(_gN, normalize(_gL + _gV))), 48.0);
            gl_FragColor.rgb += _gEnv * 0.6
                              + vec3(1.0, 0.75, 0.05) * _gFr * 0.4
                              + vec3(1.6, 1.3, 0.25)  * _gSp;
            #include <dithering_fragment>`
        );
    };
    mat.customProgramCacheKey = () => 'gold_deform_v2';
    return { mat, uniforms };
}

// ── Fire surface material (animated FBM fire, for ChickenFireHead meshes) ─────
const _FIRE_VERT = /* glsl */`
uniform float uStretch;
uniform float uTwist;
uniform float uBend;
uniform float uBreathe;
varying vec2 vUv;
void main() {
    vUv = uv;
    vec3 transformed = position;

    transformed.y *= uStretch;
    float _inv = 1.0 / sqrt(max(abs(uStretch), 0.01));
    transformed.xz *= _inv;

    float _ta = transformed.y * uTwist;
    float _ts = sin(_ta), _tc = cos(_ta);
    transformed.xz = mat2(_tc, -_ts, _ts, _tc) * transformed.xz;

    float _b = transformed.y * uBend;
    transformed.z += _b * abs(_b);

    float _bAmt = sin(uBreathe * 2.5) * 0.5 + 0.5;
    float _bW   = smoothstep(0.0, 0.5, transformed.y);
    transformed.y  += _bAmt * _bW * 0.035;
    transformed.xz *= 1.0 + _bAmt * _bW * 0.01;

    gl_Position = projectionMatrix * modelViewMatrix * vec4(transformed, 1.0);
}`;

const _FIRE_FRAG = /* glsl */`
uniform float uTime;
varying vec2 vUv;

float _fhash(vec2 p) { p = fract(p * vec2(234.34, 435.346)); p += dot(p, p + 34.23); return fract(p.x * p.y); }
float _fnoise(vec2 p) {
    vec2 i = floor(p), f = fract(p), u = f * f * (3.0 - 2.0 * f);
    return mix(mix(_fhash(i), _fhash(i+vec2(1,0)), u.x), mix(_fhash(i+vec2(0,1)), _fhash(i+vec2(1,1)), u.x), u.y);
}
float _ffbm(vec2 p) { return _fnoise(p)*0.50 + _fnoise(p*2.1+5.3)*0.32 + _fnoise(p*4.3+11.5)*0.18; }

void main() {
    vec2 uv = vUv;
    uv.y -= uTime * 0.72;
    uv.x += sin(uTime * 0.45 + vUv.y * 3.2) * 0.065;
    float n    = _ffbm(uv * vec2(3.2, 2.5));
    float sx   = pow(1.0 - abs(vUv.x * 2.0 - 1.0), 0.55);
    float sy   = pow(1.0 - vUv.y, 0.38);
    float fire = smoothstep(0.26, 0.72, n * sx * sy * 1.55);
    if (fire < 0.01) discard;
    float pulse = 0.78 + 0.22 * sin(uTime * 2.2 + 5.4);
    vec3 c = vec3(0.9, 0.08, 0.0);
    c = mix(c, vec3(1.0, 0.48, 0.0),  smoothstep(0.0,  0.38, fire));
    c = mix(c, vec3(1.0, 0.86, 0.10), smoothstep(0.38, 0.68, fire));
    c = mix(c, vec3(1.0, 1.0,  0.82), smoothstep(0.68, 1.0,  fire));
    gl_FragColor = vec4(c * pulse, fire);
}`;

// deformUniforms — if passed, the fire heads share the exact same uniform objects
// as the chicken body, so all GSAP deform animations apply to both simultaneously.
export function createFireSurfaceMaterial(deformUniforms) {
    const def = (key, val) => deformUniforms?.[key] ?? { value: val };
    const uniforms = {
        uTime:    { value: 0 },
        uStretch: def('uStretch', 1.0),
        uTwist:   def('uTwist',   0.0),
        uBend:    def('uBend',    0.0),
        uBreathe: def('uBreathe', 0.0),
    };
    const mat = new THREE.ShaderMaterial({
        vertexShader:   _FIRE_VERT,
        fragmentShader: _FIRE_FRAG,
        uniforms,
        transparent: true,
        depthWrite:  false,
        side:        THREE.DoubleSide,
    });
    return { mat, uniforms };
}

/**
 * Создаёт материал для Aurora-оверлеев (textureAtlasAurora.png + deform).
 * deformUniforms — если переданы, меши разделяют те же uniform-объекты что и тело курицы.
 */
export function createAuroraDeformMaterial(deformUniforms) {
    const def = (key, val) => deformUniforms?.[key] ?? { value: val };
    const uniforms = {
        uStretch:      def('uStretch',      1.0),
        uTwist:        def('uTwist',        0.0),
        uBend:         def('uBend',         0.0),
        uBreathe:      def('uBreathe',      0.0),
        uShadowFactor: def('uShadowFactor', 0.0),
    };
    const mat = new THREE.MeshStandardMaterial({
        map:                 auroraAtlasTexture,
        vertexColors:        false,
        flatShading:         false,
        roughness:           0.75,
        metalness:           0.0,
        polygonOffset:       true,
        polygonOffsetFactor: -2,
        polygonOffsetUnits:  -2,
    });
    mat.onBeforeCompile = (shader) => injectDeform(shader, uniforms);
    mat.customProgramCacheKey = () => 'aurora_deform_v1';
    return { mat, uniforms };
}
